// APIKeys.swift
import Foundation

enum APIKeys {
    
    private static let infoDictionary: [String: Any] = {
        guard let dict = Bundle.main.infoDictionary else {
            fatalError("Info.plist not found")
        }
        return dict
    }()
    
    static let googleMapsAPIKey: String = {
        guard let key = infoDictionary["GOOGLE_MAPS_API_KEY"] as? String, !key.isEmpty else {
            // For demo: fall back to UserDefaults so investors can enter keys on first launch
            if let saved = UserDefaults.standard.string(forKey: "google_maps_key"), !saved.isEmpty {
                return saved
            }
            return ""
        }
        return key
    }()
    
    static let stripePublishableKey: String = {
        guard let key = infoDictionary["STRIPE_PUBLISHABLE_KEY"] as? String, !key.isEmpty else {
            if let saved = UserDefaults.standard.string(forKey: "stripe_key"), !saved.isEmpty {
                return saved
            }
            return ""
        }
        return key
    }()
    
    static var isConfigured: Bool {
        return !googleMapsAPIKey.isEmpty && !stripePublishableKey.isEmpty
    }
    
    static func saveKeys(googleMaps: String, stripe: String) {
        UserDefaults.standard.set(googleMaps, forKey: "google_maps_key")
        UserDefaults.standard.set(stripe, forKey: "stripe_key")
    }
}

