import StripeCore

@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication,
                     didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        configureServicesIfReady()
        
        window = UIWindow(frame: UIScreen.main.bounds)
        
        if APIKeys.isConfigured {
            window?.rootViewController = MainTabBarController()
        } else {
            window?.rootViewController = UINavigationController(rootViewController: KeySetupViewController())
        }
        
        window?.makeKeyAndVisible()
        return true
    }
    
    func configureServicesIfReady() {
        if !APIKeys.googleMapsAPIKey.isEmpty {
            GMSServices.provideAPIKey(APIKeys.googleMapsAPIKey)
        }
        if !APIKeys.stripePublishableKey.isEmpty {
            StripeAPI.defaultPublishableKey = APIKeys.stripePublishableKey
        }
    }
}

