// MapViewController.swift
import UIKit
import GoogleMaps

class MapViewController: UIViewController {
    
    private var mapView: GMSMapView!
    private let locationManager = CLLocationManager()
    
    private let searchBar: UISearchBar = {
        let bar = UISearchBar()
        bar.placeholder = "Where are you going?"
        bar.searchBarStyle = .minimal
        bar.backgroundColor = .white
        bar.layer.cornerRadius = 12
        bar.layer.shadowColor = UIColor.black.cgColor
        bar.layer.shadowOpacity = 0.15
        bar.layer.shadowOffset = CGSize(width: 0, height: 2)
        bar.layer.shadowRadius = 8
        bar.translatesAutoresizingMaskIntoConstraints = false
        return bar
    }()
    
    private let bookRideButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Book a Ride", for: .normal)
        button.titleLabel?.font = UIFont.systemFont(ofSize: 18, weight: .bold)
        button.backgroundColor = UIColor.systemBlue
        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 16
        button.layer.shadowColor = UIColor.systemBlue.cgColor
        button.layer.shadowOpacity = 0.4
        button.layer.shadowOffset = CGSize(width: 0, height: 4)
        button.layer.shadowRadius = 8
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let rideOptionsView: RideOptionsView = {
        let view = RideOptionsView()
        view.translatesAutoresizingMaskIntoConstraints = false
        view.isHidden = true
        return view
    }()
    
    // Demo driver locations
    private let demoDrivers: [(name: String, lat: Double, lng: Double, eta: String)] = [
        ("Alex M.", 37.7749, -122.4194, "3 min"),
        ("Sarah K.", 37.7760, -122.4170, "5 min"),
        ("Mike R.", 37.7735, -122.4210, "7 min"),
        ("Lisa T.", 37.7770, -122.4150, "4 min"),
        ("James W.", 37.7740, -122.4230, "6 min"),
    ]
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "RideNow"
        navigationController?.navigationBar.prefersLargeTitles = false
        
        setupMap()
        setupUI()
        setupLocationManager()
        addDemoDriverMarkers()
        
        bookRideButton.addTarget(self, action: #selector(bookRideTapped), for: .touchUpInside)
        searchBar.delegate = self
    }
    
    private func setupMap() {
        let camera = GMSCameraPosition.camera(
            withLatitude: 37.7749,
            longitude: -122.4194,
            zoom: 15.0
        )
        
        let mapOptions = GMSMapViewOptions()
        mapOptions.camera = camera
        
        mapView = GMSMapView(options: mapOptions)
        mapView.isMyLocationEnabled = true
        mapView.settings.myLocationButton = true
        mapView.settings.compassButton = true
        mapView.delegate = self
        mapView.translatesAutoresizingMaskIntoConstraints = false
        
        // Apply custom map style for a premium look
        if let styleURL = Bundle.main.url(forResource: "MapStyle", withExtension: "json"),
           let style = try? GMSMapStyle(contentsOfFileURL: styleURL) {
            mapView.mapStyle = style
        }
        
        view.addSubview(mapView)
        
        NSLayoutConstraint.activate([
            mapView.topAnchor.constraint(equalTo: view.topAnchor),
            mapView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            mapView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            mapView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
        ])
    }
    
    private func setupUI() {
        view.addSubview(searchBar)
        view.addSubview(bookRideButton)
        view.addSubview(rideOptionsView)
        
        NSLayoutConstraint.activate([
            searchBar.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 8),
            searchBar.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            searchBar.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            searchBar.heightAnchor.constraint(equalToConstant: 52),
            
            rideOptionsView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            rideOptionsView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            rideOptionsView.bottomAnchor.constraint(equalTo: bookRideButton.topAnchor, constant: -12),
            rideOptionsView.heightAnchor.constraint(equalToConstant: 200),
            
            bookRideButton.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 24),
            bookRideButton.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -24),
            bookRideButton.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -16),
            bookRideButton.heightAnchor.constraint(equalToConstant: 56),
        ])
    }
    
    private func setupLocationManager() {
        locationManager.delegate = self
        locationManager.requestWhenInUseAuthorization()
        locationManager.startUpdatingLocation()
    }
    
    private func addDemoDriverMarkers() {
        for driver in demoDrivers {
            let marker = GMSMarker()
            marker.position = CLLocationCoordinate2D(latitude: driver.lat, longitude: driver.lng)
            marker.title = driver.name
            marker.snippet = "ETA: \(driver.eta)"
            marker.icon = createDriverIcon()
            marker.map = mapView
            
            animateMarkerArrival(marker)
        }
    }
    
    private func createDriverIcon() -> UIImage {
        let size = CGSize(width: 40, height: 40)
        let renderer = UIGraphicsImageRenderer(size: size)
        return renderer.image { ctx in
            UIColor.systemBlue.setFill()
            ctx.cgContext.fillEllipse(in: CGRect(origin: .zero, size: size))
            
            let carEmoji = "🚗" as NSString
            let attrs: [NSAttributedString.Key: Any] = [
                .font: UIFont.systemFont(ofSize: 22)
            ]
            let emojiSize = carEmoji.size(withAttributes: attrs)
            let point = CGPoint(
                x: (size.width - emojiSize.width) / 2,
                y: (size.height - emojiSize.height) / 2
            )
            carEmoji.draw(at: point, withAttributes: attrs)
        }
    }
    
    private func animateMarkerArrival(_ marker: GMSMarker) {
        marker.opacity = 0
        DispatchQueue.main.asyncAfter(deadline: .now() + Double.random(in: 0.3...1.5)) {
            UIView.animate(withDuration: 0.5) {
                marker.opacity = 1
            }
        }
    }
    
    @objc private func bookRideTapped() {
        if rideOptionsView.isHidden {
            showRideOptions()
        } else {
            confirmRide()
        }
    }
    
    private func showRideOptions() {
        rideOptionsView.isHidden = false
        rideOptionsView.alpha = 0
        rideOptionsView.transform = CGAffineTransform(translationX: 0, y: 50)
        
        UIView.animate(withDuration: 0.4, delay: 0, usingSpringWithDamping: 0.8, initialSpringVelocity: 0.5) {
            self.rideOptionsView.alpha = 1
            self.rideOptionsView.transform = .identity
        }
        
        bookRideButton.setTitle("Confirm Ride — $12.50", for: .normal)
        bookRideButton.backgroundColor = UIColor.systemGreen
    }
    
    private func confirmRide() {
        let rideConfirmVC = RideConfirmationViewController()
        rideConfirmVC.modalPresentationStyle = .pageSheet
        
        if let sheet = rideConfirmVC.sheetPresentationController {
            sheet.detents = [.medium(), .large()]
            sheet.prefersGrabberVisible = true
        }
        
        present(rideConfirmVC, animated: true)
    }
    
    private func drawRoute(from: CLLocationCoordinate2D, to: CLLocationCoordinate2D) {
        let path = GMSMutablePath()
        path.add(from)
        
        // Create a curved demo route
        let midLat = (from.latitude + to.latitude) / 2 + 0.002
        let midLng = (from.longitude + to.longitude) / 2 - 0.001
        path.add(CLLocationCoordinate2D(latitude: midLat, longitude: midLng))
        path.add(to)
        
        let polyline = GMSPolyline(path: path)
        polyline.strokeColor = UIColor.systemBlue
        polyline.strokeWidth = 5.0
        polyline.map = mapView
        
        // Add pickup and dropoff markers
        let pickupMarker = GMSMarker(position: from)
        pickupMarker.title = "Pickup"
        pickupMarker.icon = GMSMarker.markerImage(with: .systemGreen)
        pickupMarker.map = mapView
        
        let dropoffMarker = GMSMarker(position: to)
        dropoffMarker.title = "Dropoff"
        dropoffMarker.icon = GMSMarker.markerImage(with: .systemRed)
        dropoffMarker.map = mapView
        
        // Fit camera to show entire route
        let bounds = GMSCoordinateBounds(path: path)
        let cameraUpdate = GMSCameraUpdate.fit(bounds, withPadding: 80)
        mapView.animate(with: cameraUpdate)
    }
}

extension MapViewController: CLLocationManagerDelegate {
    func locationManager(_ manager: CLLocationManager, didUpdateLocations locations: [CLLocation]) {
        guard let location = locations.first else { return }
        let camera = GMSCameraPosition.camera(
            withLatitude: location.coordinate.latitude,
            longitude: location.coordinate.longitude,
            zoom: 15.0
        )
        mapView.animate(to: camera)
        manager.stopUpdatingLocation()
    }
}

extension MapViewController: GMSMapViewDelegate {
    func mapView(_ mapView: GMSMapView, didTap marker: GMSMarker) -> Bool {
        // Show driver info
        let driverInfoVC = DriverInfoViewController(driverName: marker.title ?? "Driver", eta: marker.snippet ?? "")
        driverInfoVC.modalPresentationStyle = .pageSheet
        if let sheet = driverInfoVC.sheetPresentationController {
            sheet.detents = [.medium()]
            sheet.prefersGrabberVisible = true
        }
        present(driverInfoVC, animated: true)
        return true
    }
    
    func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
        // Demo: draw route to tapped location
        let currentCenter = mapView.camera.target
        drawRoute(from: currentCenter, to: coordinate)
        showRideOptions()
    }
}

extension MapViewController: UISearchBarDelegate {
    func searchBarSearchButtonClicked(_ searchBar: UISearchBar) {
        searchBar.resignFirstResponder()
        
        // Demo destinations
        let demoDestination = CLLocationCoordinate2D(latitude: 37.7849, longitude: -122.4094)
        let currentCenter = mapView.camera.target
        drawRoute(from: currentCenter, to: demoDestination)
        showRideOptions()
    }
}

// RideOptionsView.swift
import UIKit

class RideOptionsView: UIView {
    
    private var selectedIndex: Int = 0
    
    private let rideTypes: [(name: String, price: String, time: String, icon: String)] = [
        ("Economy", "$8.50", "3 min", "🚗"),
        ("Comfort", "$12.50", "5 min", "🚙"),
        ("Premium", "$22.00", "7 min", "🚘"),
    ]
    
    private let stackView: UIStackView = {
        let stack = UIStackView()
        stack.axis = .vertical
        stack.spacing = 8
        stack.translatesAutoresizingMaskIntoConstraints = false
        return stack
    }()
    
    override init(frame: CGRect) {
        super.init(frame: frame)
        setupView()
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    private func setupView() {
        backgroundColor = .systemBackground
        layer.cornerRadius = 20
        layer.maskedCorners = [.layerMinXMinYCorner, .layerMaxXMinYCorner]
        layer.shadowColor = UIColor.black.cgColor
        layer.shadowOpacity = 0.15
        layer.shadowOffset = CGSize(width: 0, height: -3)
        layer.shadowRadius = 10
        
        addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.topAnchor.constraint(equalTo: topAnchor, constant: 16),
            stackView.leadingAnchor.constraint(equalTo: leadingAnchor, constant: 16),
            stackView.trailingAnchor.constraint(equalTo: trailingAnchor, constant: -16),
            stackView.bottomAnchor.constraint(equalTo: bottomAnchor, constant: -16),
        ])
        
        for (index, ride) in rideTypes.enumerated() {
            let optionView = createRideOption(ride: ride, index: index)
            stackView.addArrangedSubview(optionView)
        }
        
        updateSelection()
    }
    
    private func createRideOption(ride: (name: String, price: String, time: String, icon: String), index: Int) -> UIView {
        let container = UIView()
        container.layer.cornerRadius = 12
        container.layer.borderWidth = 2
        container.layer.borderColor = UIColor.clear.cgColor
        container.tag = index
        container.translatesAutoresizingMaskIntoConstraints = false
        container.heightAnchor.constraint(equalToConstant: 52).isActive = true
        
        let tap = UITapGestureRecognizer(target: self, action: #selector(optionTapped(_:)))
        container.addGestureRecognizer(tap)
        
        let iconLabel = UILabel()
        iconLabel.text = ride.icon
        iconLabel.font = UIFont.systemFont(ofSize: 28)
        iconLabel.translatesAutoresizingMaskIntoConstraints = false
        
        let nameLabel = UILabel()
        nameLabel.text = ride.name
        nameLabel.font = UIFont.systemFont(ofSize: 16, weight: .semibold)
        nameLabel.translatesAutoresizingMaskIntoConstraints = false
        
        let timeLabel = UILabel()
        timeLabel.text = ride.time
        timeLabel.font = UIFont.systemFont(ofSize: 14, weight: .regular)
        timeLabel.textColor = .secondaryLabel
        timeLabel.translatesAutoresizingMaskIntoConstraints = false
        
        let priceLabel = UILabel()
        priceLabel.text = ride.price
        priceLabel.font = UIFont.systemFont(ofSize: 16, weight: .bold)
        priceLabel.textAlignment = .right
        priceLabel.translatesAutoresizingMaskIntoConstraints = false
        
        container.addSubview(iconLabel)
        container.addSubview(nameLabel)
        container.addSubview(timeLabel)
        container.addSubview(priceLabel)
        
        NSLayoutConstraint.activate([
            iconLabel.leadingAnchor.constraint(equalTo: container.leadingAnchor, constant: 12),
            iconLabel.centerYAnchor.constraint(equalTo: container.centerYAnchor),
            
            nameLabel.leadingAnchor.constraint(equalTo: iconLabel.trailingAnchor, constant: 12),
            nameLabel.topAnchor.constraint(equalTo: container.topAnchor, constant: 8),
            
            timeLabel.leadingAnchor.constraint(equalTo: iconLabel.trailingAnchor, constant: 12),
            timeLabel.bottomAnchor.constraint(equalTo: container.bottomAnchor, constant: -8),
            
            priceLabel.trailingAnchor.constraint(equalTo: container.trailingAnchor, constant: -12),
            priceLabel.centerYAnchor.constraint(equalTo: container.centerYAnchor),
        ])
        
        return container
    }
    
    @objc private func optionTapped(_ gesture: UITapGestureRecognizer) {
        guard let view = gesture.view else { return }
        selectedIndex = view.tag
        updateSelection()
    }
    
    private func updateSelection() {
        for (index, view) in stackView.arrangedSubviews.enumerated() {
            UIView.animate(withDuration: 0.2) {
                if index == self.selectedIndex {
                    view.layer.borderColor = UIColor.systemBlue.cgColor
                    view.backgroundColor = UIColor.systemBlue.withAlphaComponent(0.08)
                } else {
                    view.layer.borderColor = UIColor.separator.cgColor
                    view.backgroundColor = UIColor.secondarySystemBackground
                }
            }
        }
    }
}

