        button.setTitleColor(.white, for: .normal)
        button.layer.cornerRadius = 12
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    private let tableView: UITableView = {
        let tv = UITableView(frame: .zero, style: .insetGrouped)
        tv.translatesAutoresizingMaskIntoConstraints = false
        return tv
    }()
    
    private let paymentMethods: [(icon: String, name: String, detail: String)] = [
        ("creditcard.fill", "Visa •••• 4242", "Default"),
        ("creditcard.fill", "Mastercard •••• 8888", ""),
        ("apple.logo", "Apple Pay", "Connected"),
        ("dollarsign.circle.fill", "Wallet", "$150.00"),
    ]
    
    private let recentTransactions: [(desc: String, amount: String, date: String)] = [
        ("Ride to Financial District", "-$12.50", "Today"),
        ("Wallet Top-up", "+$50.00", "Yesterday"),
        ("Ride to Airport", "-$35.00", "Dec 18"),
        ("Promo Credit", "+$10.00", "Dec 15"),
        ("Ride to Downtown", "-$8.75", "Dec 14"),
    ]
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Payment"
        view.backgroundColor = .systemGroupedBackground
        
        setupUI()
        
        tableView.delegate = self
        tableView.dataSource = self
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "PaymentCell")
        tableView.register(UITableViewCell.self, forCellReuseIdentifier: "TransactionCell")
        
        addFundsButton.addTarget(self, action: #selector(addFundsTapped), for: .touchUpInside)
        
        navigationItem.rightBarButtonItem = UIBarButtonItem(
            image: UIImage(systemName: "plus.circle.fill"),
            style: .plain,
            target: self,
            action: #selector(addPaymentMethod)
        )
    }
    
    private func setupUI() {
        // Balance card
        balanceCard.addSubview(balanceLabel)
        balanceCard.addSubview(amountLabel)
        balanceCard.addSubview(addFundsButton)
        
        view.addSubview(balanceCard)
        view.addSubview(tableView)
        
        NSLayoutConstraint.activate([
            balanceCard.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 16),
            balanceCard.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 16),
            balanceCard.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -16),
            balanceCard.heightAnchor.constraint(equalToConstant: 160),
            
            balanceLabel.topAnchor.constraint(equalTo: balanceCard.topAnchor, constant: 24),
            balanceLabel.leadingAnchor.constraint(equalTo: balanceCard.leadingAnchor, constant: 24),
            
            amountLabel.topAnchor.constraint(equalTo: balanceLabel.bottomAnchor, constant: 8),
            amountLabel.leadingAnchor.constraint(equalTo: balanceCard.leadingAnchor, constant: 24),
            
            addFundsButton.trailingAnchor.constraint(equalTo: balanceCard.trailingAnchor, constant: -24),
            addFundsButton.bottomAnchor.constraint(equalTo: balanceCard.bottomAnchor, constant: -20),
            addFundsButton.widthAnchor.constraint(equalToConstant: 130),
            addFundsButton.heightAnchor.constraint(equalToConstant: 40),
            
            tableView.topAnchor.constraint(equalTo: balanceCard.bottomAnchor, constant: 8),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
        ])
    }
    
    @objc private func addFundsTapped() {
        presentStripePayment(amount: 5000) // $50.00
    }
    
    @objc private func addPaymentMethod() {
        presentStripePayment(amount: 0)
    }
    
    private func presentStripePayment(amount: Int) {
        // In production, you'd fetch a PaymentIntent client secret from your backend.
        // For demo, we show Stripe's native UI with a simulated flow.
        
        let alert = UIAlertController(
            title: "Add Funds",
            message: "Select amount to add to wallet",
            preferredStyle: .actionSheet
        )
        
        let amounts = [("$10.00", 1000), ("$25.00", 2500), ("$50.00", 5000), ("$100.00", 10000)]
        
        for (label, cents) in amounts {
            alert.addAction(UIAlertAction(title: label, style: .default) { [weak self] _ in
                self?.processPayment(amountCents: cents, displayAmount: label)
            })
        }
        
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func processPayment(amountCents: Int, displayAmount: String) {
        // Demo: Show a loading state then success
        let loadingVC = PaymentProcessingViewController(amount: displayAmount)
        loadingVC.modalPresentationStyle = .overFullScreen
        loadingVC.modalTransitionStyle = .crossDissolve
        present(loadingVC, animated: true)
        
        // Simulate Stripe processing
        DispatchQueue.main.asyncAfter(deadline: .now() + 2.0) {
            loadingVC.showSuccess { [weak self] in
                // Update balance
                let currentBalance = 150.00
                let addedAmount = Double(amountCents) / 100.0
                let newBalance = currentBalance + addedAmount
                self?.amountLabel.text = String(format: "$%.2f", newBalance)
                self?.tableView.reloadData()
            }
        }
    }
}

extension PaymentViewController: UITableViewDelegate, UITableViewDataSource {
    
    func numberOfSections(in tableView: UITableView) -> Int {
        return 2
    }
    
    func tableView(_ tableView: UITableView, titleForHeaderInSection section: Int) -> String? {
        return section == 0 ? "Payment Methods" : "Recent Transactions"
    }
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return section == 0 ? paymentMethods.count : recentTransactions.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        if indexPath.section == 0 {
            let cell = tableView.dequeueReusableCell(withIdentifier: "PaymentCell", for: indexPath)
            let method = paymentMethods[indexPath.row]
            
            var config = cell.defaultContentConfiguration()
            config.image = UIImage(systemName: method.icon)
            config.text = method.name
            config.secondaryText = method.detail
            config.imageProperties.tintColor = .systemBlue
            cell.contentConfiguration = config
            cell.accessoryType = .disclosureIndicator
            
            return cell
        } else {
            let cell = tableView.dequeueReusableCell(withIdentifier: "TransactionCell", for: indexPath)
            let transaction = recentTransactions[indexPath.row]
            
            var config = cell.defaultContentConfiguration()
            config.text = transaction.desc
            config.secondaryText = transaction.date
            
            let amountLabel = UILabel()
            amountLabel.text = transaction.amount
            amountLabel.font = UIFont.systemFont(ofSize: 16, weight: .semibold)
            amountLabel.textColor = transaction.amount.hasPrefix("+") ? .systemGreen : .label
            amountLabel.sizeToFit()
            cell.accessoryView = amountLabel
            
            cell.contentConfiguration = config
            return cell
        }
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
    }
}

// PaymentProcessingViewController.swift
import UIKit

class PaymentProcessingViewController: UIViewController {
    
    private let amount: String
    private var completionHandler: (() -> Void)?
    
    private let containerView: UIView = {
        let view = UIView()
        view.backgroundColor = .systemBackground
        view.layer.cornerRadius = 24
        view.layer.shadowColor = UIColor.black.cgColor
        view.layer.shadowOpacity = 0.2
        view.layer.shadowOffset = CGSize(width: 0, height: 8)
        view.layer.shadowRadius = 20
        view.translatesAutoresizingMaskIntoConstraints = false
        return view
    }()
    
    private let spinner: UIActivityIndicatorView = {
        let spinner = UIActivityIndicatorView(style: .large)
        spinner.color = .systemBlue
        spinner.translatesAutoresizingMaskIntoConstraints = false
        return spinner
    }()
    
    private let statusLabel: UILabel = {
        let label = UILabel()
        label.text = "Processing Payment..."
        label.font = UIFont.systemFont(ofSize: 18, weight: .semibold)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let amountDisplayLabel: UILabel = {
        let label = UILabel()
        label.font = UIFont.systemFont(ofSize: 32, weight: .bold)
        label.textColor = UIColor.systemBlue
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let successImageView: UIImageView = {
        let config = UIImage.SymbolConfiguration(pointSize: 50, weight: .bold)
        let iv = UIImageView(image: UIImage(systemName: "checkmark.circle.fill", withConfiguration: config))
        iv.tintColor = .systemGreen
        iv.alpha = 0
        iv.translatesAutoresizingMaskIntoConstraints = false
        return iv
    }()
    
    init(amount: String) {
        self.amount = amount
        super.init(nibName: nil, bundle: nil)
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = UIColor.black.withAlphaComponent(0.4)
        
        amountDisplayLabel.text = amount
        
        view.addSubview(containerView)
        containerView.addSubview(spinner)
        containerView.addSubview(statusLabel)
        containerView.addSubview(amountDisplayLabel)
        containerView.addSubview(successImageView)
        
        NSLayoutConstraint.activate([
            containerView.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            containerView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            containerView.widthAnchor.constraint(equalToConstant: 280),
            containerView.heightAnchor.constraint(equalToConstant: 260),
            
            amountDisplayLabel.topAnchor.constraint(equalTo: containerView.topAnchor, constant: 32),
            amountDisplayLabel.centerXAnchor.constraint(equalTo: containerView.centerXAnchor),
            
            spinner.centerXAnchor.constraint(equalTo: containerView.centerXAnchor),
            spinner.centerYAnchor.constraint(equalTo: containerView.centerYAnchor),
            
            successImageView.centerXAnchor.constraint(equalTo: containerView.centerXAnchor),
            successImageView.centerYAnchor.constraint(equalTo: containerView.centerYAnchor),
            
            statusLabel.bottomAnchor.constraint(equalTo: containerView.bottomAnchor, constant: -32),
            statusLabel.centerXAnchor.constraint(equalTo: containerView.centerXAnchor),
            statusLabel.leadingAnchor.constraint(equalTo: containerView.leadingAnchor, constant: 16),
            statusLabel.trailingAnchor.constraint(equalTo: containerView.trailingAnchor, constant: -16),
        ])
        
        spinner.startAnimating()
    }
    
    func showSuccess(completion: @escaping () -> Void) {
        self.completionHandler = completion
        
        UIView.animate(withDuration: 0.3) {
            self.spinner.alpha = 0
        } completion: { _ in
            self.spinner.stopAnimating()
            
            self.successImageView.transform = CGAffineTransform(scaleX: 0.1, y: 0.1)
            UIView.animate(withDuration: 0.5, delay: 0, usingSpringWithDamping: 0.6, initialSpringVelocity: 0.8) {
                self.successImageView.alpha = 1
                self.successImageView.transform = .identity
            }
            
            self.statusLabel.text = "Payment Successful!"
            self.statusLabel.textColor = .systemGreen
            self.amountDisplayLabel.textColor = .systemGreen
            
            // Haptic feedback
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.success)
            
            DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) {
                self.dismiss(animated: true) {
                    self.completionHandler?()
                }
            }
        }
    }
}

