        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let routeLabel: UILabel = {
        let label = UILabel()
        label.font = UIFont.systemFont(ofSize: 15, weight: .semibold)
        label.numberOfLines = 2
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let dateLabel: UILabel = {
        let label = UILabel()
        label.font = UIFont.systemFont(ofSize: 13, weight: .regular)
        label.textColor = .secondaryLabel
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let priceLabel: UILabel = {
        let label = UILabel()
        label.font = UIFont.systemFont(ofSize: 16, weight: .bold)
        label.textAlignment = .right
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let driverLabel: UILabel = {
        let label = UILabel()
        label.font = UIFont.systemFont(ofSize: 12, weight: .regular)
        label.textColor = .tertiaryLabel
        label.textAlignment = .right
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    override init(style: UITableViewCell.CellStyle, reuseIdentifier: String?) {
        super.init(style: style, reuseIdentifier: reuseIdentifier)
        setupCell()
    }
    
    required init?(coder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }
    
    private func setupCell() {
        contentView.addSubview(statusBadge)
        contentView.addSubview(routeLabel)
        contentView.addSubview(dateLabel)
        contentView.addSubview(priceLabel)
        contentView.addSubview(driverLabel)
        
        NSLayoutConstraint.activate([
            statusBadge.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 12),
            statusBadge.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            statusBadge.widthAnchor.constraint(equalToConstant: 72),
            statusBadge.heightAnchor.constraint(equalToConstant: 20),
            
            routeLabel.topAnchor.constraint(equalTo: statusBadge.bottomAnchor, constant: 6),
            routeLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            routeLabel.trailingAnchor.constraint(equalTo: priceLabel.leadingAnchor, constant: -8),
            
            dateLabel.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -12),
            dateLabel.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            
            priceLabel.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 16),
            priceLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            priceLabel.widthAnchor.constraint(equalToConstant: 80),
            
            driverLabel.topAnchor.constraint(equalTo: priceLabel.bottomAnchor, constant: 4),
            driverLabel.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
        ])
    }
    
    func configure(status: String, from: String, to: String, price: String, date: String, driver: String) {
        routeLabel.text = "\(from) → \(to)"
        dateLabel.text = date
        priceLabel.text = price
        driverLabel.text = driver
        statusBadge.text = status
        
        if status == "Completed" {
            statusBadge.backgroundColor = UIColor.systemGreen
        } else if status == "Cancelled" {
            statusBadge.backgroundColor = UIColor.systemRed
            priceLabel.textColor = .secondaryLabel
        } else {
            statusBadge.backgroundColor = UIColor.systemOrange
        }
    }
}

